Serial.Open();
string? line;
while ((line = Serial.ReadLine()) != null)
{
    int hi = Convert.ToInt32(line.Substring(0,2), 16);
    int lo = Convert.ToInt32(line.Substring(2,2), 16);
    double temp = (hi * 256 + lo) / 10.0;
    Print($"温度: {temp:F1}°C");
}
